import { DEFAULT_DATA_POINT_RADIUS } from '../../../../core/constants.js';
import {
  AREA_VARIANT,
  BAR_VARIANT,
  DOT_VARIANT,
  LINE_VARIANT,
  RECT_VARIANT,
} from '../../../types/xy-chart-internals.js';

export function getPrevailingShapeType(
  dotDistance: number = Infinity,
  lineDistance: number = Infinity,
  areaDistance: number = Infinity,
  rectPresent: boolean = false,
  barPresent: boolean = false,
) {
  if (
    dotDistance === Infinity &&
    lineDistance === Infinity &&
    areaDistance === Infinity &&
    !rectPresent &&
    !barPresent
  ) {
    return undefined;
  }

  const threshold = DEFAULT_DATA_POINT_RADIUS * 2;

  const distances = [
    { type: LINE_VARIANT, distance: lineDistance },
    { type: DOT_VARIANT, distance: dotDistance },
    { type: AREA_VARIANT, distance: areaDistance },
  ] as const;
  const closestContinuous = distances.reduce(
    (closest, current) =>
      current.distance < closest.distance ? current : closest,
    distances[0],
  );

  if (barPresent) {
    if (closestContinuous.distance < threshold) {
      return closestContinuous.type;
    }
    return BAR_VARIANT;
  }

  if (rectPresent) {
    if (closestContinuous.distance < threshold) {
      return closestContinuous.type;
    }
    return RECT_VARIANT;
  }

  return closestContinuous.type;
}
